// HMAC-SHA256 + anti-replay timestamp verification for batch-sentinel webhook.
// Differences vs sentry-ingest (legacy) :
//   - secret env : $env.N8N_BATCH_SENTINEL_WEBHOOK_SECRET
//   - signature header : X-Signature-256 (= 'sha256=<hex>')
//   - extra check : X-Timestamp drift <= 300s (anti-replay)
const crypto = require('crypto');

const secret = $env.N8N_BATCH_SENTINEL_WEBHOOK_SECRET;
if (!secret) throw new Error('N8N_BATCH_SENTINEL_WEBHOOK_SECRET env not set');

const item = $input.first();
const itemJson = item.json || {};
const headers = itemJson.headers || {};

const rawSigHeader = headers['x-signature-256'] || headers['X-Signature-256'];
const tsHeader = headers['x-timestamp'] || headers['X-Timestamp'];
if (!rawSigHeader || !tsHeader) {
  return { json: { _hmac_status: 'missing_signature', _statusCode: 401 } };
}

const tsNum = Number(tsHeader);
if (!Number.isFinite(tsNum)) {
  return { json: { _hmac_status: 'invalid_timestamp', _statusCode: 400 } };
}
const nowSec = Math.floor(Date.now() / 1000);
if (Math.abs(nowSec - tsNum) > 300) {
  return { json: { _hmac_status: 'stale_timestamp', _statusCode: 401 } };
}

const presentedHex = rawSigHeader.startsWith('sha256=') ? rawSigHeader.slice(7) : rawSigHeader;

const binaryData = item.binary && item.binary.data;
if (!binaryData || !binaryData.data) {
  return { json: { _hmac_status: 'raw_body_unavailable_binary', _statusCode: 500 } };
}
const rawBuf = Buffer.from(binaryData.data, 'base64');
const expectedHex = crypto.createHmac('sha256', secret).update(rawBuf).digest('hex');

const presentedBuf = Buffer.from(presentedHex, 'hex');
const expectedBuf = Buffer.from(expectedHex, 'hex');
if (presentedBuf.length !== expectedBuf.length || !crypto.timingSafeEqual(presentedBuf, expectedBuf)) {
  return { json: { _hmac_status: 'invalid_signature', _statusCode: 401 } };
}

const bodyObj = itemJson.body || {};
return { json: { ...bodyObj, _hmac_status: 'ok' } };

// Validate batch outcome payload schema. Reject malformed payloads with 400.
const body = $json;

const required = [
  ['workflow_name', body.workflow_name],
  ['conclusion', body.conclusion],
  ['run_id', body.run_id],
  ['run_url', body.run_url],
  ['completed_at', body.completed_at],
  ['attempt', body.attempt],
];
for (const [name, value] of required) {
  if (value === undefined || value === null || value === '') {
    return { json: { ...body, _schema_status: 'missing_field', _field: name, _statusCode: 400 } };
  }
}

const validConclusions = ['success', 'failure', 'cancelled', 'timed_out', 'action_required', 'skipped', 'neutral'];
if (!validConclusions.includes(body.conclusion)) {
  return { json: { ...body, _schema_status: 'invalid_conclusion', _field: 'conclusion', _statusCode: 400 } };
}

return {
  json: {
    ...body,
    _schema_status: 'ok',
    _external_id: 'batch:' + body.workflow_name,
  },
};

// Append success outcome to static data for the daily digest aggregate.
// Pruning : remove entries older than 25h (1h margin over the 24h digest window).
const body = $json;
const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd.batch_outcomes)) sd.batch_outcomes = [];

sd.batch_outcomes.push({
  workflow_name: body.workflow_name,
  conclusion: body.conclusion,
  run_url: body.run_url,
  completed_at: body.completed_at,
  duration_s: body.duration_s ?? null,
  attempt: body.attempt,
});

const cutoffMs = Date.now() - 25 * 60 * 60 * 1000;
sd.batch_outcomes = sd.batch_outcomes.filter((e) => {
  const t = new Date(e.completed_at).getTime();
  return Number.isFinite(t) && t >= cutoffMs;
});

return { json: { ...body, _appended: true, _branch: 'success' } };

// Build a Sentry-compatible event payload for GlitchTip ingest.
// GlitchTip is Sentry-API compatible: POST <DSN_BASE>/api/<project_id>/store/
// with header X-Sentry-Auth (or query param sentry_key). The `fingerprint`
// field controls dedup/grouping — using 'batch:<workflow_name>' gives us
// idempotent create + auto-reopen on regression at the GlitchTip side, which
// replaces the previous Notion lookup/route/create/reopen/increment graph.
//
// The DSN comes from $env.GLITCHTIP_DSN_N8N_WORKFLOWS. Format :
//   http://<public_key>@<host>:<port>/<project_id>
// We split it once here to derive the ingest URL + sentry_key for the next
// HTTP node (n8n expressions don't let us URL-parse cleanly downstream).
const body = $('Schema Validation').first().json;

const dsn = $env.GLITCHTIP_DSN_N8N_WORKFLOWS;
if (!dsn) throw new Error('GLITCHTIP_DSN_N8N_WORKFLOWS env not set');
const dsnMatch = dsn.match(/^(https?:\/\/)([^@]+)@([^/]+)\/(\d+)$/);
if (!dsnMatch) throw new Error('GLITCHTIP_DSN_N8N_WORKFLOWS malformed (expected http://<key>@<host>/<id>)');
const [, scheme, publicKey, host, projectId] = dsnMatch;
const ingestUrl = `${scheme}${host}/api/${projectId}/store/?sentry_key=${publicKey}`;

const severityByConclusion = {
  failure: 'error',
  cancelled: 'warning',
  timed_out: 'warning',
  action_required: 'warning',
};
const level = severityByConclusion[body.conclusion] || 'warning';

const nowIso = new Date().toISOString();
const eventPayload = {
  // Sentry SDK 'event' protocol — minimal fields.
  timestamp: nowIso,
  platform: 'other',
  level,
  logger: 'n8n.batch-sentinel',
  message: `Batch ${body.workflow_name} concluded with ${body.conclusion} on attempt ${body.attempt}.`,
  // fingerprint = stable dedup key → GlitchTip reuses the same issue on regression
  // and increments occurrence count natively. Replaces the legacy External ID logic.
  fingerprint: ['batch:' + body.workflow_name],
  tags: {
    source: 'batch',
    workflow: body.workflow_name,
    conclusion: body.conclusion,
    severity: level,
  },
  extra: {
    workflow_name: body.workflow_name,
    conclusion: body.conclusion,
    run_id: body.run_id,
    run_url: body.run_url,
    commit_sha: body.commit_sha || null,
    actor: body.actor || null,
    ref: body.ref || null,
    started_at: body.started_at || null,
    completed_at: body.completed_at,
    duration_s: body.duration_s ?? null,
    attempt: body.attempt,
  },
};

const markdown = [
  `# [batch] failure: ${body.workflow_name}`,
  ``,
  `## TL;DR`,
  `Batch \`${body.workflow_name}\` concluded with \`${body.conclusion}\` on attempt ${body.attempt}.`,
  ``,
  `## Run`,
  `- URL: ${body.run_url}`,
  `- Commit: ${body.commit_sha || 'unknown'}`,
  `- Actor: ${body.actor || 'unknown'}`,
  `- Ref: ${body.ref || 'unknown'}`,
  `- Started at: ${body.started_at || 'unknown'}`,
  `- Completed at: ${body.completed_at}`,
  `- Duration: ${body.duration_s == null ? 'unknown' : body.duration_s + 's'}`,
].join('\n');

return {
  json: {
    ...body,
    _glitchtip_ingest_url: ingestUrl,
    _glitchtip_payload: eventPayload,
    _markdown_string: markdown,
  },
};

// Quarantine fallback (GlitchTip ingest failed after 3 retries).
// Writes the Markdown payload to /quarantine so a human operator can review
// and replay later. /quarantine is bind-mounted by docker-compose.yml.
const fs = require('fs');
const path = require('path');

const markdown = $('Build GlitchTip Payload').first().json._markdown_string || '';
const eventBody = $('Schema Validation').first().json;
const externalIdSlug = (eventBody._external_id || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '-');
const tsSlug = new Date().toISOString().replace(/[:.]/g, '-');
const filePath = `/quarantine/batch-${tsSlug}-${externalIdSlug}.md`;

let writeStatus = 'ok';
let writeError = null;
try {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, markdown, { encoding: 'utf8', mode: 0o600 });
} catch (e) {
  writeStatus = 'failed';
  writeError = String(e?.message || e);
}

return {
  json: {
    ...$json,
    _quarantine_path: filePath,
    _quarantine_status: writeStatus,
    _quarantine_error: writeError,
  },
};

// Append failure outcome to static data (counted in digest). Same pruning
// rule as success path.
const body = $('Schema Validation').first().json;
const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd.batch_outcomes)) sd.batch_outcomes = [];

sd.batch_outcomes.push({
  workflow_name: body.workflow_name,
  conclusion: body.conclusion,
  run_url: body.run_url,
  completed_at: body.completed_at,
  duration_s: body.duration_s ?? null,
  attempt: body.attempt,
});

const cutoffMs = Date.now() - 25 * 60 * 60 * 1000;
sd.batch_outcomes = sd.batch_outcomes.filter((e) => {
  const t = new Date(e.completed_at).getTime();
  return Number.isFinite(t) && t >= cutoffMs;
});

return { json: { ...body, _appended: true, _branch: 'failure' } };

// Structured log line for Promtail/Loki ingestion.
const body = $json;
let latency_ms = null;
try {
  const startedAt = (typeof $execution !== 'undefined' && $execution?.startedAt) ? $execution.startedAt : null;
  if (startedAt) {
    const startMs = new Date(startedAt).getTime();
    if (!Number.isNaN(startMs)) latency_ms = Date.now() - startMs;
  }
} catch (_) {}

console.log(JSON.stringify({
  level: 'info',
  ts: new Date().toISOString(),
  service: 'n8n',
  workflow: 'batch-sentinel',
  event: 'webhook_received',
  workflow_name: body.workflow_name,
  conclusion: body.conclusion,
  branch: body._branch || 'success',
  external_id: body._external_id || ('batch:' + body.workflow_name),
  latency_ms,
}));

return { json: body };

// batch-sentinel digest — agrège la santé des batchs sur 24h depuis static data.
const NOW = Date.now();
const WINDOW_MS = 24 * 60 * 60 * 1000;
const cutoff = NOW - WINDOW_MS;

const dateLabel = new Date(NOW).toLocaleString('fr-FR', {
  timeZone: 'Europe/Paris', day: '2-digit', month: '2-digit',
  hour: '2-digit', minute: '2-digit',
});

const sd = $getWorkflowStaticData('global');
const outcomes = Array.isArray(sd.batch_outcomes) ? sd.batch_outcomes : [];
const recent = outcomes.filter((e) => {
  const t = new Date(e.completed_at).getTime();
  return Number.isFinite(t) && t >= cutoff;
});

if (recent.length === 0) {
  return { json: { content: `📊 Ratis batchs — 24h (${dateLabel})\n• 0 run batch reporté dans la fenêtre` } };
}

const perWorkflow = {};
for (const e of recent) {
  if (!perWorkflow[e.workflow_name]) {
    perWorkflow[e.workflow_name] = { total: 0, success: 0, failure: 0, failures_urls: [] };
  }
  const bucket = perWorkflow[e.workflow_name];
  bucket.total += 1;
  if (e.conclusion === 'success') {
    bucket.success += 1;
  } else {
    bucket.failure += 1;
    if (bucket.failures_urls.length < 3) bucket.failures_urls.push(e.run_url);
  }
}

const totalRuns = recent.length;
const totalSuccess = recent.filter((e) => e.conclusion === 'success').length;
const totalFailure = totalRuns - totalSuccess;

const lines = [];
lines.push(`📊 Ratis batchs — 24h (${dateLabel})`);
lines.push(`• total : ${totalRuns} (${totalSuccess} ✅ / ${totalFailure} ❌)`);
lines.push(`• détails :`);
for (const [name, stats] of Object.entries(perWorkflow)) {
  const icon = stats.failure > 0 ? '❌' : '✅';
  lines.push(`  ${icon} ${name} — ${stats.success}✅/${stats.failure}❌ (n=${stats.total})`);
}
if (totalFailure > 0) {
  lines.push(`• échecs (run urls) :`);
  for (const [name, stats] of Object.entries(perWorkflow)) {
    for (const url of stats.failures_urls) {
      lines.push(`  • ${name}: ${url}`);
    }
  }
}

return { json: { content: lines.join('\n') } };
